// Lôi toàn bộ data chảy từ Supabase sang
const txns = $input.all(); 

// Sắp xếp mảng theo thứ tự Ngày giờ giảm dần (Mới nhất lên đầu)
txns.sort((a, b) => {
    const dateA = a.json.date ? new Date(a.json.date) : new Date(0);
    const dateB = b.json.date ? new Date(b.json.date) : new Date(0);
    return dateB - dateA; // Thời gian lớn hơn (mới hơn) sẽ trồi lên trên
});

let totalIncome = 0;
let totalExpense = 0;
let validTxnCount = 0; 
let historyStr = []; 

// Chạy Vòng lặp Cộng trừ và Xử lý múi giờ
txns.forEach((row) => {
    const data = row.json;

    // Màng lọc Giao dịch Khóa/Bị Xóa Mềm
    if (data.is_deleted === true || data.isdeleted === true) {
        return; 
    }

    validTxnCount++;
    const amount = Number(data.amount) || 0; 

    if (data.is_expense === true) {
        totalExpense += amount;
    } else {
        totalIncome += amount;
    }

    // Cộng 7 tiếng và định dạng lại
    let formattedDateTime = 'N/A';
    if (data.date) {
        // Tạo đối tượng Date từ chuỗi UTC trong Database
        const utcDate = new Date(data.date);
        // Cộng thêm 7 tiếng (7 * 60 * 60 * 1000 ms)
        const vnDate = new Date(utcDate.getTime() + (7 * 60 * 60 * 1000));

        // Định dạng ngày giờ theo kiểu Việt Nam (DD/MM/YYYY HH:mm)
        const d = vnDate.getDate().toString().padStart(2, '0');
        const m = (vnDate.getMonth() + 1).toString().padStart(2, '0');
        const y = vnDate.getFullYear();
        const hr = vnDate.getHours().toString().padStart(2, '0');
        const min = vnDate.getMinutes().toString().padStart(2, '0');

        formattedDateTime = `${d}/${m}/${y} ${hr}:${min}`;
    }

    // Gửi dòng dữ liệu đã chuẩn hóa sang cho AI (Dùng đơn vị USD cho khớp logic hệ thống)
    const tBody = `- [${formattedDateTime}] [${data.category_name}] ${data.is_expense ? 'Chi' : 'Thu'} ${amount.toLocaleString('en-US')} USD (${data.note || 'Trống'})`;
    historyStr.push(tBody);
});

// Trả về báo cáo (hiển thị đơn vị là USD)
return [{
  json: {
    tong_thu: totalIncome.toLocaleString('en-US') + " USD",
    tong_chi: totalExpense.toLocaleString('en-US') + " USD",
    so_du: (totalIncome - totalExpense).toLocaleString('en-US') + " USD",
    tong_so_giao_dich: validTxnCount,
    kich_ban_lich_su: historyStr.join("\n")
  }
}];
